INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD1', N'Tai nghe chụp tai chống ồn Apple AirPods Max 2 2026 | Chính hãng Apple Việt Nam', N'Apple Chính hãng', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/a/tai_nghe_ch_p_tai_ch_ng_n_apple_airpods_max_2026_1__1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/a/tai_nghe_ch_p_tai_ch_ng_n_apple_airpods_max_2026_2__1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/a/tai_nghe_ch_p_tai_ch_ng_n_apple_airpods_max_2026_3__1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/a/tai_nghe_ch_p_tai_ch_ng_n_apple_airpods_max_2026_4_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/a/tai_nghe_ch_p_tai_ch_ng_n_apple_airpods_max_2026_3_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/a/tai_nghe_ch_p_tai_ch_ng_n_apple_airpods_max_2026_5_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/a/tai_nghe_ch_p_tai_ch_ng_n_apple_airpods_max_2026_7__1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/a/tai_nghe_ch_p_tai_ch_ng_n_apple_airpods_max_2026_7_.png"]', N'{"Kích thước & Trọng lượng": {"Kích thước": "168.6 x 187.3 x 83.4 mm", "Trọng lượng": "AirPods Max 2, bao gồm đệm tai: 386,2 gram\nSmart Case: 134,5 gram"}, "Công nghệ âm thanh": {"Công nghệ âm thanh": "Trình điều khiển động do Apple thiết kế\nBộ khuếch đại với độ lệch tương phản cao có thể tùy chỉnh\nChủ Động Khử Tiếng Ồn Âm Thanh Thích Ứng\nChế độ Xuyên Âm\nNhận Biết Cuộc Hội Thoại\nTách Lời Nói\nÂm Lượng Được Cá Nhân Hóa\nGiảm Âm", "Micro": "Tổng cộng chín micrô:\nTám micrô dành cho tính năng Chủ Động Khử Tiếng Ồn\nBa micrô dành cho tính năng nhận diện giọng nói (hai micrô dùng chung với tính năng Chủ Động Khử Tiếng Ồn và một micrô bổ sung)", "Tính năng": "Xuyên âm, Có mic đàm thoại, Chống ồn chủ động ANC", "Cảm biến": "Cảm biến quang học (mỗi bên củ tai)\nCảm biến vị trí (mỗi bên củ tai)\nCảm biến phát hiện hộp (mỗi bên củ tai)\nGia tốc kế (mỗi bên củ tai)\nCon quay hồi chuyển (củ tai bên trái)"}, "Khả năng kết nối": {"Bluetooth": "5.3"}, "Thời lượng pin - sạc": {"Thời lượng sử dụng Pin": "Lên đến 20 giờ với một lần sạc khi bật tính năng Chủ Động Khử Tiếng Ồn", "Cổng sạc": "Cáp Sạc USB-C"}, "Điều khiển": {"Thao tác điều khiển": "Digital Crown\nXoay để điều khiển âm lượng\nNhấn một lần để phát hoặc tạm dừng phương tiện\nNhấn một lần để trả lời cuộc gọi, bật hoặc tắt tiếng\nNhấn một lần để mở điều khiển camera\nNhấn hai lần để kết thúc cuộc gọi\nNhấn hai lần để tua tớ"}, "Tính năng - Tiện ích khác": {"Tính năng khác": "Các tính năng Trợ Năng giúp người khuyết tật tận dụng tối đa AirPods Max mới của mình.\nCác tính năng bao gồm:\nÂm thanh Nghe Trực Tiếp\nMức âm thanh tai nghe\nThích Nghi Tai Nghe"}, "Vi xử lý & đồ họa": {"Chipset": "Chip tai nghe Apple H2 (mỗi bên củ tai)"}, "Thông tin hãng": {"Hãng sản xuất": "Apple Chính hãng"}}', 'CAT1');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD2', N'Balo máy ảnh Sakos Imapro', N'Tomtoc', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2026-03-12t144004.124.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/h/thi_t_k_ch_a_c_t_n_26__3.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-max-innostyle-with-magsafe-tim_-_2026-03-12t144021.083.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-max-innostyle-with-magsafe-tim_-_2026-03-12t144039.471.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-max-innostyle-with-magsafe-tim_-_2026-03-12t144049.978.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-max-innostyle-with-magsafe-tim_-_2026-03-12t144031.140.png"]', N'{"Kích thước & Trọng lượng": {"Kích thước": "29 x 19 x 43 cm", "Trọng lượng": "1.7 kg\nTải trọng 15 kg"}, "Thông tin hãng": {"Hãng sản xuất": "Tomtoc"}, "Thiết kế & Trọng lượng": {"Chất liệu": "Polyester"}, "Thông số khác": {"Tiện ích": "Ngăn chính mở 90 độ\nHơn 10 ngăn phụ\nDây kéo có màn bảo vệ hạn chế rạch\nĐệm lưng EVA thoát nhiệt\nQuai đeo to bản, lót mút êm ái\nTay cầm có đệm mút êm tay"}}', 'CAT1');
