INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD21', N'Bàn phím cơ không dây Aula F108 Hồng Gradient', N'Aula', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/_/m_y_c_o_r_u_22_51__2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/_/m_y_c_o_r_u_22_52__2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/_/m_y_c_o_r_u_22_53__2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/_/m_y_c_o_r_u_22_54__2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/_/m_y_c_o_r_u_22_55__2.png"]', N'{"Tổng quan": {"Loại bàn phím": "Full-size", "Số phím": "108 phím", "Keycap": "PBT Double-Shot", "Tương thích": "WINXP/WIN7/WIN8/WIN10/Android/IOS/MAC"}, "Kết nối và đèn LED": {"Kết nối": "3 mode có dây Type-C & không dây 2.4G & BT", "Khoảng cách kết nối (Độ dài dây)": "Lên đến 10m", "Đèn LED": "LED RGB 15 hiệu ứng ánh sáng"}, "Pin và tiện ích": {"Pin": "Pin lithium 8000mAh có thể sạc lại", "Tiện ích": "Độ bền phím: 60 triệu lần bấm\nHiệu ứng âm thanh khi gõ phím: Linear\nHot-swap 5 pin\nGasket mount\nMạch xuôi\nSố lượng phím: 108 phím\nĐiện áp định mức: DC 3.7V\nĐiện áp/ dòng điện: DC 5V/ ≤1200mA"}, "Thiết kế và khối lượng": {"Kích thước": "44.52 × 14.15 × 4.29 ± 0.01 cm", "Khối lượng": "Khoảng 1000g (Không bao gồm dây cáp và đầu thu)/ Khoảng 1048g (Bao gồm cáp và đầu thu)"}, "Thông tin hãng": {"Hãng sản xuất": "Aula"}}', 'CAT1');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD22', N'Bàn phím cơ không dây AULA F75 Hồng Gradient', N'Aula', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/_/m_y_c_o_r_u_22_46__3.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/_/m_y_c_o_r_u_22_48__2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/_/m_y_c_o_r_u_22_47__2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/_/m_y_c_o_r_u_22_49__2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/_/m_y_c_o_r_u_22_50__2.png"]', N'{"Tổng quan": {"Loại bàn phím": "Tenkeyless 75%", "Số phím": "80 phím", "Keycap": "Nhựa PBT 2 màu", "Phím đặc biệt": "Phím tăng giảm âm lượng/độ sáng của đèn", "Tương thích": "WINXP/WIN7/WIN8/WIN10\nAndroid/IOS/MAC", "Nút nhấn": "Hiệu ứng âm thanh khi gõ phím: Linear"}, "Kết nối và đèn LED": {"Kết nối": "3 mode có dây Type-C & không dây 2.4G & Bluetooth", "Khoảng cách kết nối (Độ dài dây)": "Độ dài dây:1.6m", "Đèn LED": "LED RGB 16.8 triệu màu, 16 loại hiệu ứng"}, "Pin và tiện ích": {"Pin": "Pin lithium 4000mAh có thể sạc lại\nThời gian sạc khoảng 4 tiếng", "Thời gian dùng": "Khoảng 30.5 giờ (hiệu ứng ánh sáng mặc định) và khoảng 80 giờ (tắt led)", "Tiện ích": "Hot-Swap 5 pin\nGasket mount\nNúm xoay đa chức năng\nMàn hình hiển thị thông tin và hình ảnh\nMạch xuôi\nThiết kế cấu trúc gasket với sáu lớp vật liệu cách âm\nĐiện áp/dòng sạc: DC 5V-1050mA\nĐiện áp định mức: DC 3.7V (đầy đủ 4.2V)\n5 lớp giảm tiếng ồn\nCấu trúc đệm Leaf Spring\nTấm định vị PC có rãnh\nMiếng đệm cách âm PET\nBông giảm thanh PORON\nPhím đơn PCB có rãnh 1.2mm", "Chất liệu": "Khuôn silicone ở dưới cùng", "Cổng sạc": "Dây sạc Type-C"}, "Thiết kế và khối lượng": {"Kích thước": "32.27 × 14.32 × 4.31 cm", "Khối lượng": "Khoảng 975g (không có cáp/bộ thu)/ 1023g (với cáp/bộ thu)"}, "Thông tin hãng": {"Hãng sản xuất": "Aula"}}', 'CAT1');
