INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD42', N'Bút cảm ứng iPad Baseus Smooth Writing 3 Wired Charging Stylus Active Wireless', N'Baseus', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2026-03-31t115727.392.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-airpods-pro-3-ravaka-breeds-xanh-duong_40_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2026-03-31t115813.031.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2026-03-31t115805.200.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2026-03-31t115825.860.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2026-03-31t115832.566.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2026-03-31t115819.549.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2026-03-31t120010.125.png"]', N'{"Pin & công nghệ sạc": {"Pin": "Thời lượng sử dụng: lên đến 17 giờ\nDung lượng pin: 140mAh\nChip tiêu thụ điện năng thấp"}, "Kích thước & Trọng lượng": {"Kích thước": "Chiều dài: 165 mm\nĐường kính: 9 mm", "Trọng lượng": "15.5g"}, "Thông tin hãng": {"Hãng sản xuất": "Baseus"}, "Thiết kế & Trọng lượng": {"Chất liệu": "Thân bút: Hợp kim nhôm\nĐầu bút: POM (Polyoxymethylene)"}, "Thông số kỹ thuật": {"Cổng sạc ra": "Sạc có dây qua cổng Type-C"}, "Thông số khác": {"Tiện ích": "Công nghệ chống nhiễu LDS\nĐầu bút mạ vàng tăng độ ổn định tín hiệu\nHỗ trợ 32 chức năng tùy chỉnh chỉ với 1 lần chạm\nNút bấm vật lý tích hợp trên thân bút\nTự động bật khi cầm lên (Auto Wake)\nTích hợp AI và cảm biến lực nhấn chính xác", "Tương thích": "Nắp chống bụi tích hợp cho cổng sạc\nĐèn LED hiển thị trạng thái hoạt động\nCác chức năng hỗ trợ gồm: Về màn hình chính (Home), Nguồn (Power), Điều chỉnh độ sáng, Ứng dụng gần đây, Tăng/giảm âm lượng, Chuyển trang trước/sau, Tắt tiếng, Tìm kiếm, Chụp ảnh, Chụp màn hình nhanh, Chỉnh sửa screenshot, Palm rejection (chống chạm nhầm)"}}', 'CAT1');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD43', N'Bút cảm ứng Xiaomi Pen Pro 2026', N'Xiaomi', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/b/u/but-cam-ung-xiaomi-pocus-pen-pro_1_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/b/u/but-cam-ung-xiaomi-pocus-pen-pro_2_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/b/u/but-cam-ung-xiaomi-pocus-pen-pro_4_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/b/u/but-cam-ung-xiaomi-pocus-pen-pro_3_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/b/u/but-cam-ung-xiaomi-pocus-pen-pro_5_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/b/u/but-cam-ung-xiaomi-pocus-pen-pro_6_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/b/u/but-cam-ung-xiaomi-pocus-pen-pro_7_.png"]', N'{"Pin & công nghệ sạc": {"Pin": "100 mAh"}, "Kích thước & Trọng lượng": {"Kích thước": "160 x 8.8 mm", "Trọng lượng": "17.5 g"}, "Thông tin hãng": {"Hãng sản xuất": "Xiaomi"}, "Tiện ích": {"Tính năng khác": "Viết khi màn hình tắt\nĐộ nhạy áp lực 16.384 cấp độ\nĐộ trễ cực thấp\nTốc độ lấy mẫu cảm ứng 240Hz\nNăm mức cài đặt lực nhấn có thể điều chỉnh"}}', 'CAT1');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD44', N'Camera hành trình Insta 360 Ace Pro 2 chính hãng', N'Insta360', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-insta360-ace-pro-2-standard-1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-insta360-ace-pro-2-standard-7.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-insta360-ace-pro-2-standard-8.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-insta360-ace-pro-2-standard-9.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-insta360-ace-pro-2-standard-10.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-insta360-ace-pro-2-standard-11.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-insta360-ace-pro-2-standard-6.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-insta360-ace-pro-2-standard-3.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-insta360-ace-pro-2-standard-2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-insta360-ace-pro-2-standard-4.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-insta360-ace-pro-2-standard-5.jpg"]', N'{"Kích thước & Trọng lượng": {"Kích thước": "71,9 x 52,2 x 38mm", "Trọng lượng": "177,2g"}, "Dòng camera": {"Dòng camera": "Camera hành động"}, "Thông số camera": {"Độ phân giải": "50MP (8192x6144)\n37MP (8192x4608)\n12.5MP (4096x3072)\n9MP (4096x2304)", "Cảm biến ảnh": "1/1,3\"", "Chip xử lý": "2 chip AI", "Góc ống kính": "Khẩu độ: F2.6\nGóc nhìn: 157° (Leica Ultra Wide)", "Chất lượng video": "8K (16:9): 7680x4320\n8K (2.35:1): 7680x3272\n4K (4:3): 3840×2880\n4K (16:9): 3840x2160\n4K (2.35:1): 3840x1632\n2.7K (4:3): 2688x2016\n2.7K (16:9): 2688x1520\n1440p (4:3): 1920x1440\n1080p (16:9): 1920x1080\nChế độ Purevideo 4k60fps", "Ghi âm": "3 Micro", "Thông số màn hình": "Giá trị phơi sáng: ±4EV\nPhạm vi ISO: 100-6400\nTốc độ màn trập Ảnh: 1/8000 - 120 giây, Video: 1/8000 - đến giới hạn khung hình mỗi giây\nCân bằng trắng: 2000–10000K (tự động)\nBitrate tối đa: lên đến 180Mbps"}, "Lưu trữ và kết nối": {"Bộ nhớ": "Hỗ trợ thẻ nhớ microSD lên đến 1TB", "Kết nối không dây": "Bluetooth: BLE 5.2\nWi-Fi: 2,4 GHz, 5 GHz 802.11 a/b/g/n/ac", "Ứng dụng hỗ trợ": "Insta360 App"}, "Nguồn điện": {"Thông số pin": "1800mAh\nThời gian sạc: 47 phút (với sạc nhanh 30W) 75 phút với sạc 5V/3A Thời gian sử dụng: 180 phút"}, "Tính năng": {"Chống rung": "FlowState và khóa đường chân trời 360°", "Quay phim siêu chậm": "4K (16:9): 3840x2160@120/100fps\n2.7K (16:9):2688x1520@120/100fps\n1080p (16:9): 1920x1080@240/200/120/100fps", "Tính năng khác": "Chống nước 12m (60m với hộp lặn)\nMàn hình cảm ứng lật 2,5\"\nKiểm soát bằng cử chỉ\nĐiều khiển bằng giọng nói 2.0"}, "Thông tin hãng": {"Hãng sản xuất": "Insta360"}, "Thông số kỹ thuật": {"Cổng sạc ra": "USB-C 3.0"}, "Tiện ích": {"Tính năng khác": "Định dạng video: MP4\nĐịnh dạng ảnh: JPG DNG RAW\nMã hoá video: H.264, H.265\nChế độ âm thanh: Giảm gió, Tăng cường giọng nói, Âm thanh nổi\nĐịnh dạng âm thanh: 48 kHz, 16-bit, AAC"}, "Thông số khác": {"Tiện ích": "Chế độ video: Video (có Active HDR tích hợp), FreeFrame Video, PureVideo, Chuyển động chậm, Starlapse, Timelapse, TimeShift, Ghi vòng lặp, Dashcam, Ghi trước\nChế độ ảnh: Ảnh, Ảnh HDR, Ảnh Interval, Ảnh Burst, Chụp nhanh hình sao"}}', 'CAT1');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD45', N'Camera hành trình Vietmap TS-C1', N'Vietmap', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-o-to-vietmap-ts-c1_2__2.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-o-to-vietmap-ts-c1_3_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-o-to-vietmap-ts-c1_4_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-o-to-vietmap-ts-c1_2_.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-o-to-vietmap-ts-c1_1_.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-o-to-vietmap-ts-c1_3_.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-o-to-vietmap-ts-c1_4_.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-o-to-vietmap-ts-c1_5_.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-hanh-trinh-o-to-vietmap-ts-c1_6_.jpg"]', N'{"Thông số kỹ thuật": {"Dòng điện vào": "5V/1.5A"}, "Dòng camera": {"Dòng camera": "Dùng cho Oto", "Vị trí lắp đặt trên xe": "Gắn kính chắn gió"}, "Thông số camera": {"Cảm biến ảnh": "G-Sensor", "Góc ống kính": "Góc rộng 150°", "Chất lượng video": "Full HD (1920 x 1080p)", "Ghi âm": "Có", "Thông số màn hình": "LCD 0.96 inch"}, "Lưu trữ và kết nối": {"Bộ nhớ": "MicroSD (Hỗ trợ thẻ tối đa 128GB)", "Kết nối không dây": "Wi-Fi", "Ứng dụng hỗ trợ": "VIETMAP REC"}, "Nguồn điện": {"Nguồn điện trực tiếp": "5V - 1.5A", "Thông số pin": "Siêu tụ"}, "Tính năng": {"Kết nối phụ kiện rời": "Giá đỡ 3M", "Tính năng khác": "Kết nối WIFI chia sẻ video\nGhi hình vòng lặp khi thẻ nhớ đầy\nDễ dàng lắp đặt, không gây cản trở tầm nhìn\nTự động khóa và bảo vệ video khi xảy ra va chạm, rung lắc"}, "Thông tin hãng": {"Hãng sản xuất": "Vietmap"}}', 'CAT1');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD46', N'Camera IP Wifi 360° 2K 3MP TP-Link Tapo C245D', N'TP-Link', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ip-wifi-2-2k-3mp-tp-link-tapo-c245.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ip-wifi-2-2k-3mp-tp-link-tapo-c245d-4.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ip-wifi-2-2k-3mp-tp-link-tapo-c245d-5.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ip-wifi-2-2k-3mp-tp-link-tapo-c245d-6.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ip-wifi-2-2k-3mp-tp-link-tapo-c245d-7.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ip-wifi-2-2k-3mp-tp-link-tapo-c245d-8.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ip-wifi-2-2k-3mp-tp-link-tapo-c245d-9.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ip-wifi-2-2k-3mp-tp-link-tapo-c245d-10.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ip-wifi-2-2k-3mp-tp-link-tapo-c245d-11.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ip-wifi-2-2k-3mp-tp-link-tapo-c245d-12.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ip-wifi-2-2k-3mp-tp-link-tapo-c245d-1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ip-wifi-2-2k-3mp-tp-link-tapo-c245d-2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/c/a/camera-ip-wifi-2-2k-3mp-tp-link-tapo-c245d-3.jpg"]', N'{"Thông số chính": {"Dòng camera": "Camera trong nhà, Camera Wifi", "Độ phân giải": "3MP (2304 × 1296)", "Góc ống kính": "Ống kính kép: Wide 121.8° (chéo), Tele 65° (chéo)", "Góc nhìn": "Ống wide: 104.3° (ngang), 57.9° (dọc)\nỐng tele: 56.5° (ngang), 30.6° (dọc)", "Góc xoay": "Xoay ngang 340° (quan sát 360°)\nXoay dọc 70° (bao phủ 100°)", "Cảm biến ảnh": "1/2.8” CMOS Starlight", "Tầm nhìn": "Hồng ngoại ban đêm (IR) 12m"}, "Lưu trữ và kết nối": {"Kết nối": "WiFi 2.4GHz (802.11 b/g/n)", "Bộ nhớ": "Hỗ trợ thẻ nhớ, Lưu trữ đám mây", "Chuẩn lưu trữ": "MicroSD tối đa 512GB, H.265, hỗ trợ cloud", "Ứng dụng hỗ trợ": "Ứng dụng TP-Link Tapo", "Kết nối cùng lúc": "Nhiều thiết bị truy cập", "Tương thích": "Android 7.0+, iOS 12.0+", "Nguồn điện": "Adapter 9V - 0.85A"}, "Tính năng và tiện ích": {"Tính năng": "Phát hiện chuyển động & con người\nPhát hiện thú cưng, phương tiện, âm thanh\nTheo dõi chuyển động thông minh\nĐàm thoại 2 chiều, mic & loa tích hợp\nXoay 360° quan sát toàn cảnh\nGửi cảnh báo thời gian thực về điện thoại\nThiết lập vùng cảnh báo\nHỗ trợ Google Assistant & Alexa\nLưu trữ thẻ nhớ & cloud", "Bảo mật": "Mã hóa AES 128-bit, SSL/TLS, WPA/WPA2/WPA3", "Điều kiện hoạt động/bảo quản": "Nhiệt độ hoạt động: 0°C ~ 40°C\nNhiệt độ lưu trữ: -20°C ~ 60°C\nĐộ ẩm hoạt động: 10% ~ 90% RH (không ngưng tụ)\nĐộ ẩm lưu trữ: 0% ~ 90% RH (không ngưng tụ)"}, "Thiết kế và trọng lượng": {"Kích thước": "82.2 × 82.2 × 126.2 mm"}, "Thông tin hãng": {"Hãng sản xuất": "TP-Link"}}', 'CAT1');
