//cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_10__6_72.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_9__11_19.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_8__11_27.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_7__7_33.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_6__7_38.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_5__12_47.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_4__10_52.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_3__10_59.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_2__13_87.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_1__9_172.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_16_18.png"]', N'{"Màn hình": {"Công nghệ màn hình": "AMOLED", "Kích thước màn hình": "1.32 inch", "Độ phân giải": "466 x 466 pixels, 353 PPI\nĐộ sáng lên đến 3.000 nits"}, "Thiết kế": {"Chất liệu mặt kính": "Kính sapphire", "Chất liệu viền": "Thép", "Thiết kế": "Mặt tròn", "Trọng lượng": "38 gram (Không dây đeo)"}, "Dây đeo": {"Chất liệu dây": "Silicone", "Bề rộng dây": "2 cm", "Có thể thay dây": "Có"}, "Tính năng": {"Nghe,gọi": "Nghe gọi qua Bluetooth", "Kháng nước": "5 ATM", "Tiện ích sức khoẻ": "Theo dõi giấc ngủ, Đo nhịp tim, Đo lượng oxy trong máu, Đo mức độ stress, Cảm biến nhiệt độ, Cảnh báo nhịp tim bất thường, Theo dõi chu kỳ, Bài tập thở", "Tính năng thể thao": "Hơn 170 chế độ\nNhận diện thông minh: 25 động tác tập luyện sức mạnh, 8 động tác thể thao\nHỗ trợ chạy bộ nâng cao: Các bài tập chạy tích hợp, kế hoạch chạy Zepp Coach, ngưỡng lactate, công suất chạy, thời gian tiếp đất, quản lý trang thiết bị chạy bộ, chế độ chạy trên đường đua, hiệu chỉnh quỹ đạo thông minh, người dẫn tốc ảo", "Thông báo": "Cuộc gọi, tin nhắn, ứng dụng", "Tiện ích khác": "Có định vị GPS, Chế độ luyện tập, Hiển thị thông báo điện thoại, Nghe gọi trên đồng hồ, Điều khiển chơi nhạc, Nhận thông báo cuộc gọi, Bấm giờ, Báo thức, Tìm điện thoại, Điều khiển chụp ảnh, Dự báo thời tiết, Nghe gọi qua Bluetooth, Loa và mic tích hợp", "Tính năng đặc biệt": "Hỗ trợ BioCharge\nTìm kiếm điểm tham quan\nĐịnh tuyến lại tự động\nLập kế hoạch tuyến đường từ điểm này đến điểm khác\nLưu trữ các podcast yêu thích"}, "Cấu hình": {"Kết nối": "5 hệ thống định vị vệ tinh\nBluetooth, BLE 5.3", "Camera": "Không", "CPU": "Không công bố", "Ram": "Không công bố", "Bộ nhớ trong": "Không công bố", "Hệ điều hành": "Khác", "Tương thích": "Android 7.0 trở lên\niOS 14.0 trở lên", "Ứng dụng kết nối": "Zepp App, Zepp Coach\nĐồng bộ với các ứng dụng thể dục của bên thứ ba: Strava, TrainingPeaks, Intervals.icu, Google Fit, Apple Health", "Cảm biến": "Cảm biến sinh trắc học BioTracker PPG (5PD + 2LED)\nCảm biến gia tốc\nCảm biến con quay hồi chuyển\nCảm biến từ trường\nMáy đo độ cao khí áp\nCảm biến ánh sáng môi trường\nCảm biến nhiệt độ"}, "Pin": {"Thời lượng pin": "Sử dụng thông thường: Lên đến 12 ngày\nSử dụng nhiều: Lên đến 7 ngày\nChế độ AOD: Lên đến 4 ngày\nGPS liên tục: Lên đến 24 giờ\nGPS liên tục khi nghe nhạc: Lên đến 10 giờ\nGPS liên tục (chế độ tiết kiệm pin): Lên đến 76 giờ", "Dung lượng pin": "365 mAh"}, "Thông tin khác": {"Ngôn ngữ": "Tiếng Việt, Tiếng Anh, Tiếng Trung", "Thời gian ra mắt": "03/2026", "Nơi sản xuất": "Trung Quốc"}, "Thông tin hãng": {"Hãng sản xuất": "Amazfit"}}', 'CAT6');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD123', N'Đồng hồ thông minh Huawei Watch GT Runner 2', N'Huawei', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dh_28.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dh_1__23.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dh_2__24.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dh_3__18.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dh_4__1_18.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dh_5__18.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dh_6__1_14.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dh_9__10.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dh_8__10.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dh_7__11.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dh_11__7.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dh_10__9.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dh_12__5.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dh_13__6.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dh_14__5.png"]', N'{"Màn hình": {"Công nghệ màn hình": "AMOLED", "Kích thước màn hình": "1.32 inch", "Độ phân giải": "466 × 466 pixel, PPI 352"}, "Thiết kế": {"Chất liệu mặt kính": "Kính Côn Luân thế hệ thứ 2", "Chất liệu viền": "Hợp kim titanium", "Thiết kế": "Mặt tròn", "Trọng lượng": "34.5 g (không bao gồm dây đeo)"}, "Dây đeo": {"Chất liệu dây": "Vải", "Kích thước cổ tay phù hợp": "Từ 12 - 19 cm", "Có thể thay dây": "Có"}, "Tính năng": {"Nghe,gọi": "Nghe gọi qua Bluetooth", "Kháng nước": "5 ATM, IP69\nLặn (Độ sâu tối đa 40 mét)", "Tiện ích sức khoẻ": "Chế độ luyện tập, Theo dõi giấc ngủ, Đo nhịp tim, Đo lượng oxy trong máu, Đếm bước chân, Tính calo tiêu thụ, Tính quãng đường chạy, Đo mức độ stress, Phát hiện té ngã, Cảnh báo nhịp tim bất thường, Đo điện tâm đồ, Theo dõi chu kỳ, Tình trạng HRV (Heart Rate Variability)", "Tính năng thể thao": "Hơn 100 chế độ thể thao\nTừ đạp xe và bơi lội đến nhảy dây\nChạy đường mòn\nGolf\nLặn tự do\nChế độ xe lăn\nĐạp xe nâng cao với FTP và công suất ảo\nChạy địa hình với tốc độ điều chỉnh độ dốc\nBản đồ hơn 17.000 sân golf trên toàn thế giới, hơn 3.000 sân tại Anh", "Thông báo": "Tin nhắn, cuộc gọi, ứng dụng", "Tiện ích khác": "Có định vị GPS, Phát nhạc trên đồng hồ, Chế độ luyện tập, Hiển thị thông báo điện thoại, Nghe gọi trên đồng hồ, Nhận thông báo cuộc gọi, Loa và mic tích hợp, Quản lý tiến độ tập luyện", "Tính năng đặc biệt": "Chế độ Marathon thông minh\nTrợ lý sự kiện\nDự đoán hiếu suất tập luyện\nPhân tích ECG"}, "Cấu hình": {"Kết nối": "NFC\nBluetooth Tần số 2.4 GHz, hỗ trợ Bluetooth 6.0 và Bluetooth + BLE\nGPS (Băng tần kép L1 + L5)/GLONASS/BeiDou (Ba băng tần B1I + B1C + B2a)/GALILEO (Băng tần kép E1 + E5a)/QZSS (Băng tần kép L1 + L5)/NavIC", "Camera": "Không", "CPU": "Không công bố", "Ram": "Không công bố", "Bộ nhớ trong": "Không công bố", "Hệ điều hành": "Khác", "Tương thích": "Android 9.0 trở lên\niOS 13.0 trở lên", "Ứng dụng kết nối": "HUAWEI Health", "Cảm biến": "Cảm biến gia tốc, cảm biến con quay hồi chuyển, cảm biến từ kế, cảm biến nhịp tim quang học, cảm biến áp suất khí quyển, cảm biến nhiệt độ, cảm biến ánh sáng môi trường, cảm biến điện tâm đồ, cảm biến độ sâu"}, "Pin": {"Thời lượng pin": "Pin có thể sử dụng được đến 14 ngày nếu dùng ít, 7 ngày nếu dùng thông thường, hoặc 32 giờ ở chế độ tập luyện ngoài trời", "Cổng sạc": "Sạc không dây"}, "Thông tin khác": {"Ngôn ngữ": "Tiếng Anh, Tiếng Trung, Tiếng Việt", "Thời gian ra mắt": "03/2026", "Nơi sản xuất": "Trung Quốc"}, "Thông tin hãng": {"Hãng sản xuất": "Huawei"}}', 'CAT6');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD124', N'Đồng hồ thông minh Xiaomi Watch S5', N'Xiaomi', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dhnn_1.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/d/h/dhnn_1__1.png"]', N'{"Màn hình": {"Công nghệ màn hình": "AMOLED", "Kích thước màn hình": "1.48 inch", "Độ phân giải": "480 x 480 pixel, độ sáng 2500 nits,"}, "Thiết kế": {"Chất liệu mặt kính": "Kính cường lực", "Chất liệu viền": "Thép", "Đường kính mặt": "46mm", "Thiết kế": "Mặt tròn", "Trọng lượng": "45.6 gram (không bao gồm dây đeo)"}, "Dây đeo": {"Chất liệu dây": "Cao Su", "Kích thước cổ tay phù hợp": "Từ 14 – 21 cm", "Có thể thay dây": "Có"}, "Tính năng": {"Nghe,gọi": "Nghe gọi qua Bluetooth", "Kháng nước": "5 ATM", "Tiện ích sức khoẻ": "Chế độ luyện tập, Theo dõi giấc ngủ, Đo nhịp tim, Đo lượng oxy trong máu, Đếm bước chân, Tính calo tiêu thụ, Tính quãng đường chạy, Đo mức độ stress, Phát hiện té ngã, Cảnh báo nhịp tim bất thường, Theo dõi chu kỳ, Bài tập thở, Bài tập thư giãn, Phát hiện chứng ngưng thở khi ngủ", "Tính năng thể thao": "Hơn 150 chế độ thể thao\nTự động nhận diện bắt đầu bài tập\nChế độ ghi Vlog thể thao\nKết nối bộ đo sức khỏe của bên thứ ba\nPhát hiện té ngã khi trượt tuyết\nNhận diện tư thế chạy\nTheo dõi hành trình (track)\nTính toán năng lượng tiêu hao\nNhắc đạt chỉ số vận động (ví dụ cho đi bộ, chạy, đạp, máy chèo, máy elip, nhảy dây)", "Thông báo": "Thông báo cuộc goi, tin nhắn, gọi xe, giao hàng, đồ ăn (taxi, giao đồ ăn, giao hàng)", "Tiện ích khác": "Có định vị GPS, Chế độ luyện tập, Hiển thị thông báo điện thoại, Tùy chỉnh mặt đồng hồ, Nghe gọi trên đồng hồ, Nhận thông báo cuộc gọi, Bấm giờ, Báo thức, Dự báo thời tiết, Xem bản đồ, Nghe gọi qua Bluetooth, Đèn pin, Tìm đồng hồ, Loa và mic tích hợp, Trả lời nhanh tin nhắn có sẵn", "Tính năng đặc biệt": "Xiaomi Super Island: mở khoá từ xa, khởi động xe\nĐiều khiển nhà thông minh trên cổ tay\nHỗ trợ bản đồ offline\nChụp ảnh màn hình trên đồng hồ\nTrợ lý giọng nói: XiaoAI (Tiểu A)\nĐiều khiển bằng cử chỉ búng tay"}, "Cấu hình": {"Kết nối": "Hỗ trợ 5 hệ thống vệ tinh: Bắc Đẩu, GPS, GLONASS, Galileo, QZSS — thu tìm vệ tinh toàn diện với chip GNSS hai tần mới\nBluetooth BLE / BT 5.4 (hỗ trợ chế độ hai kênh)\nWi‑Fi: hỗ trợ 2.4 GHz\nNFC", "GPS tích hợp": "GPS tích hợp sẵn trên đồng hồ", "Camera": "Không", "CPU": "Không công bố", "Ram": "Không công bố", "Bộ nhớ trong": "Không công bố", "Hệ điều hành": "HyperOS 3", "Tương thích": "Android 8.0 trở lên hoặc iOS 14.0 trở lên", "Ứng dụng kết nối": "Mi Fitness", "Cảm biến": "Cảm biến nhịp tim (bao gồm SpO2), cảm biến gia tốc, con quay hồi chuyển (gyroscope), cảm biến từ trường (la bàn), cảm biến áp suất khí quyển, cảm biến ánh sáng môi trường"}, "Pin": {"Thời lượng pin": "Thời lượng pin siêu dài: 21 ngày\nSử dụng thông thường: 14 ngày\nBluetooth AOD — Sử dụng thông thường: 9 ngày", "Thời gian sạc": "Không công bố", "Dung lượng pin": "815mAh", "Cổng sạc": "Nam châm"}, "Thông tin khác": {"Ngôn ngữ": "Tiếng Việt, Tiếng Anh, Tiếng Trung", "Thời gian ra mắt": "03/2026", "Nơi sản xuất": "Trung Quốc"}, "Thông tin hãng": {"Hãng sản xuất": "Xiaomi"}}', 'CAT6');
