aoAI (Tiểu A)\nĐiều khiển bằng cử chỉ búng tay"}, "Cấu hình": {"Kết nối": "Hỗ trợ 5 hệ thống vệ tinh: Bắc Đẩu, GPS, GLONASS, Galileo, QZSS — thu tìm vệ tinh toàn diện với chip GNSS hai tần mới\nBluetooth BLE / BT 5.4 (hỗ trợ chế độ hai kênh)\nWi‑Fi: hỗ trợ 2.4 GHz\nNFC", "GPS tích hợp": "GPS tích hợp sẵn trên đồng hồ", "Camera": "Không", "CPU": "Không công bố", "Ram": "Không công bố", "Bộ nhớ trong": "Không công bố", "Hệ điều hành": "HyperOS 3", "Tương thích": "Android 8.0 trở lên hoặc iOS 14.0 trở lên", "Ứng dụng kết nối": "Mi Fitness", "Cảm biến": "Cảm biến nhịp tim (bao gồm SpO2), cảm biến gia tốc, con quay hồi chuyển (gyroscope), cảm biến từ trường (la bàn), cảm biến áp suất khí quyển, cảm biến ánh sáng môi trường"}, "Pin": {"Thời lượng pin": "Thời lượng pin siêu dài: 21 ngày\nSử dụng thông thường: 14 ngày\nBluetooth AOD — Sử dụng thông thường: 9 ngày", "Thời gian sạc": "Không công bố", "Dung lượng pin": "815mAh", "Cổng sạc": "Nam châm"}, "Thông tin khác": {"Ngôn ngữ": "Tiếng Việt, Tiếng Anh, Tiếng Trung", "Thời gian ra mắt": "03/2026", "Nơi sản xuất": "Trung Quốc"}, "Thông tin hãng": {"Hãng sản xuất": "Xiaomi"}}', 'CAT6');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD127', N'Ghế massage đa năng Philips PPM8502', N'Philips', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/h/ghe-massage-da-nang-philips-ppm8502-1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/h/ghe-massage-da-nang-philips-ppm8502-2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/h/ghe-massage-da-nang-philips-ppm8502-3.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/h/ghe-massage-da-nang-philips-ppm8502-4.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/h/ghe-massage-da-nang-philips-ppm8502-5.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/h/ghe-massage-da-nang-philips-ppm8502-6.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/h/ghe-massage-da-nang-philips-ppm8502-7.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/h/ghe-massage-da-nang-philips-ppm8502-8.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/g/h/ghe-massage-da-nang-philips-ppm8502-9.jpg"]', N'{"Thông tin chung": {"Công suất": "28W", "Điều khiển": "Remote có dây", "Mức điều chỉnh": "3 cấp độ massage rung - 1 mức nhiệt - 3 thời gian massage", "Đầu massage đi kèm": "Con lăn massage 3D", "Vùng massage": "Lưng, mông, đùi"}, "Tính năng và tiện ích": {"Chế độ massage": "3 chế độ massage tự động, Chế độ chạy thử", "Chức năng": "Massage thư giãn, giảm mỏi cơ, chườm ấm", "Công nghệ": "Con lăn 3D + nhiệt 60°C", "Tiện ích": "Remote có dây\nTúi đựng remote tiện lợi\nDây thun co giãn để treo máy lên ghế\n3 thời gian massage: 5 phút, 10 phút, 15 phút\nChất liệu da pu & vải lưới thoáng khí mềm mại"}, "Nguồn điện & Thiết kế": {"Nguồn điện": "Adapter (Input 100-240V, Output 12V)\nChiều dài dây nguồn: 186.5 cm", "Chất liệu": "Da PU, vải lưới thoáng khí", "Kích thước": "105 x 42 x 6 cm\nChiều dài dây: 80cm", "Trọng lượng": "2.77 kg"}, "Thông tin hãng": {"Hãng sản xuất": "Philips"}}', 'CAT2');
