INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD226', N'Máy lọc không khí diệt khuẩn & khử mùi Acerpure Pro P2', N'Acerpure', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/a/may-loc-khong-khi-acerpure-pro-p2-1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/a/may-loc-khong-khi-acerpure-pro-p2-3.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/a/may-loc-khong-khi-acerpure-pro-p2-2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/a/may-loc-khong-khi-acerpure-pro-p2-4.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/m/a/may-loc-khong-khi-acerpure-pro-p2-5.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/p/r/pro-p2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/p/r/pro-p2-1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/p/r/pro-p2-3.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/p/r/pro-p2-2.jpg"]', N'{"Thông số kỹ thuật": {"Dòng điện vào": "220V - 240V/50Hz - 60Hz"}, "Tổng quan": {"Diện tích sử dụng": "45m2", "Hiệu quả lọc bụi": "Loại bỏ 99,97% bụi siêu mịn PM1.0", "Công suất": "38W", "Lưu lượng gió": "324 m³/h", "Màng lọc": "HEPA H13 4-in-1 (lọc thô, HEPA+, HEPA H13, than hoạt tính)", "Số màng lọc": "4", "Độ ồn": "25 - 56 dB"}, "Công nghệ và chế độ hoạt động": {"Công nghệ": "Ion âm, động cơ DC-Inverter, cảm biến chất lượng không khí thông minh", "Chế độ hoạt động": "Smart / 1 / 2 / 3 / Turbo", "Chế độ lọc": "Tự động (Smart)\nTurbo\nChế độ ngủ (Sleep)"}, "Tính năng và tiện ích": {"Tiện ích": "Điều khiển bằng điện thoại qua App, Cảnh báo nắp bộ lọc không đóng kín, Cảnh báo thay bộ lọc, Đèn báo chất lượng không khí, Đèn báo hoạt động, Điều khiển bằng remote, Khóa bảng điều khiển, Tính năng diệt khuẩn (đèn UV), Tính năng diệt khuẩn (ion âm)", "Cảm biến": "Cảm biến laser PM1.0 & PM2.5, cảm biến mùi và khí GAS (VOCs)", "Ứng dụng kết nối": "Acerpure Life", "Bảng điều khiển": "Màn hình LCD hiển thị và điều khiển cảm ứng"}, "Thiết kế và trọng lượng": {"Kích thước": "253 × 253 × 576 mm", "Trọng lượng": "4.2kg"}, "Thông tin hãng": {"Hãng sản xuất": "Acerpure"}}', 'CAT2');
