INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD308', N'Ốp lưng Samsung Galaxy S26 Plus UAG Pathfinder Clear With Magsafe', N'UAG', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2026-03-18t171248.234.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_2_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_3_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_10_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_9_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_4_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_5_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_6_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_7_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_8_.png"]', N'{"Kích thước & Trọng lượng": {"Kích thước": "Dài: 16.46 cm - Rộng: 8.20 cm - Sâu: 1.32 cm", "Trọng lượng": "41g"}, "Thông số khác": {"Dòng sản phẩm": "Samsung Galaxy S26 Plus", "Phân loại ốp": "Chống sốc", "Tính năng": "Hỗ trợ sạc MagSafe, Hỗ trợ sạc không dây, Chống sốc, va đập, Chống trầy xước", "Tiện ích": "Chống rơi: lên đến 18 ft (5.4 m)\nChống sốc/va đập: khung chống va đập + TPU gia cố\nTiêu chuẩn: đạt MIL-STD 810G-516.6 (3X drop test)\nMô-đun nam châm tích hợp\nTương thích phụ kiện từ tính\nHỗ trợ Samsung Pay", "Tương thích": "Cấu trúc:\nLớp giáp siêu nhẹ (ultra-light armor)\nLõi hoa văn hình lục giác tăng khả năng hấp thụ lực\nViền màn hình nâng cao bảo vệ màn hình\nTích hợp điểm neo dây buộc (lanyard anchor)"}, "Thông tin hãng": {"Hãng sản xuất": "UAG"}, "Thiết kế & Trọng lượng": {"Chất liệu": "Kết hợp vỏ cứng + lõi mềm chống sốc\nTPU gia cố ở viền\n25% vật liệu tái chế sau tiêu dùng (PCR)"}}', 'CAT1');
