INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD322', N'Ốp lưng Samsung Galaxy S26 Ultra UAG Chống Sốc Monarch Pro', N'UAG', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/t/e/text_ng_n_-_2026-03-19t143821.684.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_68_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_69_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_74_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_73_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_72_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_71_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_70_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_76_.png", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/o/p/op-lung-iphone-16-pro-cam-den_75_.png"]', N'{"Kích thước & Trọng lượng": {"Kích thước": "Dài: 16.99 cm - Rộng: 8.43 cm - Sâu: 1.47 cm", "Trọng lượng": "59g"}, "Thông số khác": {"Dòng sản phẩm": "Samsung Galaxy S26 Ultra", "Phân loại ốp": "Chống sốc", "Tính năng": "Chống sốc, va đập, Chống trầy xước", "Tương thích": "Chống rơi: 25 ft / 7.6 m\nTiêu chuẩn: MIL-STD 810G 516.6 (5X drop test)\nChống sốc & phân tán lực tác động\nChống trầy xước, móp méo, hao mòn hằng ngày\nBảo vệ toàn diện trong môi trường khắc nghiệt\nHỗ trợ Samsung Pay\nGrip chống trượt (tay nắm viền có vân)\nNút bấm lớn, phản hồi tốt\nCắt CNC chính xác, hỗ trợ đầy đủ S Pen\nĐiểm neo dây buộc tích hợp (không kèm dây)"}, "Thông tin hãng": {"Hãng sản xuất": "UAG"}, "Thiết kế & Trọng lượng": {"Chất liệu": "Cấu trúc 5 lớp bảo vệ (multi-layer)\nKhung giáp đặc trưng (Armor Frame)\nHoàn thiện: da cao cấp / sợi carbon\nLõi chống sốc (shock-absorbing core)\nTấm polycarbonate (PC) tăng độ cứng\nViền cao su chống va đập"}}', 'CAT1');
