INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD361', N'Robot hút bụi lau sàn Dreame D30 Ultra', N'Dreame', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-9.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-10.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-11.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-12.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-13.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-14.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-3.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-4.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-5.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-6.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-7.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-d30-ultra-8.jpg"]', N'{"Thông tin chung": {"Chức năng": "Hút bụi", "Lực hút": "25.000Pa", "Dung tích ngăn chứa bụi": "3,2L", "Ứng dụng kết nối": "Dreamhome", "Pin": "5.200mAh"}, "Tiện ích và tính năng": {"Tính năng": "Hỗ trợ tường ảo, Lưu trữ nhiều bản đồ, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Tự động điều chỉnh sức hút, Chống rối tóc - lông thú, Tự động hút bụi, Tự động giặt giẻ, Tự động sấy giẻ", "Tiện ích": "Điều khiển từ xa bằng app và giọng nói\nTTrạm dock tự động đổ rác\nKhay giặt giẻ tự làm sạch AceClean™\nThiết lập vùng cấm và tường ảo trong app\nLên lịch dọn dẹp tự động"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "Trọng lượng robot hút bụi: 3,91kg\nTrọng lượng trạm sạc: 8,62kg", "Kích thước": "Kích thước robot: 35 × 35 × 9.7 cm\nKích thước trạm sạc: 45.7 × 34 × 59 cm"}, "Thông tin hãng": {"Hãng sản xuất": "Dreame"}, "Tiện ích": {"Tính năng khác": "Lực hút Vormax™ 25.000Pa với 5 mức lực hút\nHút và lau 2 trong 1 với hệ thống lau xoay DuoScrub™\nMopExtend™ RoboSwing mở rộng giẻ lau\nTự nâng giẻ lau ~10.5 mm khi gặp thảm"}}', 'CAT2');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD362', N'Robot hút bụi lau sàn chuyên dụng Dreame F20', N'Dreame', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-13.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-8.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-9.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-10.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-11.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-12.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-3.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-4.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-5.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-6.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-f20-7.jpg"]', N'{"Thông tin chung": {"Chức năng": "Hút bụi lau sàn", "Dung tích ngăn chứa nước": "270 ml", "Lực hút": "20.000 Pa", "Dung tích ngăn chứa bụi": "220 ml", "Ứng dụng kết nối": "Dreamhome", "Pin": "3200 mAh"}, "Tiện ích và tính năng": {"Tính năng": "Hoạt động êm ái, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Chống rối tóc - lông thú", "Tiện ích": "Điều khiển từ xa bằng app và giọng nói\nTrang bị hệ thống điều hướng Smart Pathfinder™, giúp nhận diện vật cản và di chuyển thông minh\nTự quay về trạm sạc khi pin yếu\nTối ưu làm sạch khe hở và mép sàn"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "Trọng lượng robot hút bụi: 2,55kg\nTrọng lượng trạm sạc: 0,29kg", "Kích thước": "Kích thước robot: 32.5 × 32.5 × 9.47 cm\nKích thước trạm sạc: 14.6 × 6 × 9.86 cm"}, "Thông tin hãng": {"Hãng sản xuất": "Dreame"}, "Tiện ích": {"Tính năng khác": "Lực hút Vormax™ 20.000Pa làm sạch sâu\nXử lý 100%* các hạt bụi lớn\nHút và lau 2 trong 1, hỗ trợ 32 mức điều chỉnh lượng nước\nThiết lập vùng cấm lau"}}', 'CAT2');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD363', N'Robot hút bụi lau sàn chuyên dụng Dreame X50 Pro Ultra', N'Dreame', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x50-pro-ultra-5.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x50-pro-ultra-6.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x50-pro-ultra-7.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x50-pro-ultra-8.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x50-pro-ultra-9.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x50-pro-ultra-10.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x50-pro-ultra-11.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x50-pro-ultra-1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x50-pro-ultra-2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x50-pro-ultra-3.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x50-pro-ultra-4.jpg"]', N'{"Thông tin chung": {"Chức năng": "Hút bụi lau sàn", "Dung tích ngăn chứa nước": "Robot: 80 ml\nTrạm sạc: 4.5L (nước sạch) + 4L (nước bẩn)", "Lực hút": "20.000 Pa", "Dung tích ngăn chứa bụi": "Robot: 300 ml\nTrạm sạc: 3.2L", "Ứng dụng kết nối": "Dreamhome", "Pin": "6.400 mAh"}, "Tiện ích và tính năng": {"Tính năng": "Hỗ trợ tường ảo, Lưu trữ nhiều bản đồ, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Tự động điều chỉnh sức hút, Chống rối tóc - lông thú, Tự động hút bụi, Tự động giặt giẻ, Tự động sấy giẻ", "Tiện ích": "Điều khiển từ xa bằng app\nTự động đổ rác, tự giặt và sấy giẻ lau\nTự thêm nước và dung dịch lau sàn\nModule bàn chải con lăn lốc xoáy độc quyền\nHệ thống ProLeap chân cơ học đột phá"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "Trọng lượng robot hút bụi: 4,53 kg\nTrọng lượng trạm sạc: 9,09 kg", "Kích thước": "Kích thước robot: 35 x 35 x 8.9cm\nKích thước trạm sạc: 45.7 x 34 x 59cm"}, "Thông tin hãng": {"Hãng sản xuất": "Dreame"}, "Tiện ích": {"Tính năng khác": "Động cơ TurboForce6, tốc độ quay 90.000 vòng/phút\nHệ thống chổi chính kép\nAI Sage 13.0 (phân tích môi trường nhiều góc độ, lập bản đồ)\nAI camera tích hợp nhận diện vật cản, thú cưng…"}}', 'CAT2');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD364', N'Robot hút bụi lau nhà Dreame X60 Ultra', N'Dreame', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x60-ultra-7.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x60-ultra-6.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x60-ultra-8.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x60-ultra-9.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x60-ultra-10.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x60-ultra-11.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x60-ultra-12.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x60-ultra-1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x60-ultra-2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x60-ultra-3.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x60-ultra-4.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-dreame-x60-ultra-5.jpg"]', N'{"Thông tin chung": {"Chức năng": "Hút bụi lau sàn", "Dung tích ngăn chứa nước": "Nước sạch: 4,2L\nNước bẩn: 3,0L", "Lực hút": "36.000Pa", "Dung tích ngăn chứa bụi": "Túi bụi: 3,2L\nHộc bụi: 235ml", "Ứng dụng kết nối": "Dreamhome", "Pin": "6.400mAh"}, "Tiện ích và tính năng": {"Tính năng": "Hoạt động êm ái, Hỗ trợ tường ảo, Lưu trữ nhiều bản đồ, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Tự động điều chỉnh sức hút, Chống rối tóc - lông thú, Tự động hút bụi, Tự động giặt giẻ, Tự động sấy giẻ", "Tiện ích": "Điều khiển từ xa bằng app và giọng nói\nTrạm dock đa năng tự động đổ rác\nTự động giặt giẻ bằng nước nóng 100 °C\nTự động sấy khô giẻ lau bằng khí nóng\nTự quay về trạm sạc khi pin yếu\nNhấc giẻ lau 10,5 mm khi gặp thảm lông ngắn"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "Trọng lượng robot hút bụi: 4,7kg\nTrọng lượng trạm sạc: 10,6kg", "Kích thước": "Kích thước robot: 35 x 35 x 7.95cm\nKích thước trạm sạc: 39 x 42.3 x 49.9cm"}, "Thông tin hãng": {"Hãng sản xuất": "Dreame"}, "Tiện ích": {"Tính năng khác": "Lực hút Vormax™ 36.000Pa cuốn bay mọi bụi bẩn\nCông nghệ vượt chướng ngại vật FlexiAdapt™\nHệ thống AI OmniSight™ nâng cấp với camera góc rộng 120°\nTự làm sạch giẻ lau 100℃ ThermoHub™\nHệ thống DuoBrush chống rối 2.0 HyperStream™"}}', 'CAT2');
