s.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-roborock-s-pro-3.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-roborock-s-pro-4.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-roborock-s-pro-5.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-roborock-s-pro-6.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-roborock-s-pro-7.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-roborock-s-pro-8.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-roborock-s-pro-9.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-roborock-s-pro-10.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-roborock-s-pro-27.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-roborock-s-pro-28.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-roborock-s-pro-29.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-roborock-s-pro-30.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-roborock-s-pro-32.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-roborock-s-pro-31.jpg"]', N'{"Thông tin chung": {"Chức năng": "Hút bụi lau sàn", "Thời gian hoạt động": "Sử dụng: 180 phút\nSạc: 4 giờ", "Dung tích ngăn chứa nước": "80ml", "Lực hút": "18,500Pa", "Dung tích ngăn chứa bụi": "330ml", "Ứng dụng kết nối": "Roborock App", "Pin": "5,200mAh", "Độ ồn": "64dB", "Công suất": "60W"}, "Tiện ích và tính năng": {"Tính năng": "Hoạt động êm ái, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Tự động điều chỉnh sức hút, Chống rối tóc - lông thú, Tự động hút bụi, Tự động giặt giẻ, Tự động sấy giẻ", "Tiện ích": "Công nghệ Reactive Tech\nCông nghệ điều hướng PreciSense LiDAR\nCảm biến thảm siêu âm\nĐiều khiển bằng giọng nói của bên thứ ba\nGiẻ lau xoay kép 200 vòng/phút\nGiặt giẻ lau bằng nước nóng 75°C"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "11.7±0.3kg", "Kích thước": "350 x 353 x 96.5mm"}, "Thông tin hãng": {"Hãng sản xuất": "Roborock"}, "Tiện ích": {"Tính năng khác": "Khóa trẻ em và quản lý chế độ làm sạch từ xa\nLưu và quản lý nhiều bản đồ tầng\nTùy chỉnh chế độ làm sạch theo từng loại sàn và thảm"}}', 'CAT2');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD366', N'Robot hút bụi lau nhà Xiaomi Vacuum H50', N'Xiaomi', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-3.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-4.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-5.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-6.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-7.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-8.jpg"]', N'{"Thông tin chung": {"Chức năng": "Hút bụi lau sàn", "Dung tích ngăn chứa nước": "Nước sạch: 4L\nNước bẩn: 4L", "Lực hút": "10.000Pa", "Chế độ hút": "Hút bụi trước khi lau\nHút bụi\nLau nhà\nHút & lau", "Ứng dụng kết nối": "Xiaomi Home", "Pin": "4800mAh", "Công suất": "55W"}, "Tiện ích và tính năng": {"Tính năng": "Hỗ trợ tường ảo, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Chống rối tóc - lông thú, Lưu trữ một bản đồ, Tự động hút bụi, Tự động giặt giẻ, Tự động sấy giẻ", "Tiện ích": "Điều khiển qua app Xiaomi Home và giọng nói\nTự động đổ rác (túi dùng ~75 ngày)\nLàm sạch theo điểm\nLau xoay kép tốc độ cao 180rpm"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "3.7kg", "Kích thước": "355 × 353.5 × 93mm"}, "Thông tin hãng": {"Hãng sản xuất": "Xiaomi"}, "Tiện ích": {"Tính năng khác": "Điều hướng laser LDS, lập bản đồ 360°\nTự động nâng khăn lau khi gặp thảm\n4 chế độ làm sạch\nChống rối tóc (lược chữ Y + chổi chống rối)"}}', 'CAT2');
INSERT INTO Product (ProductID, ProductName, Brand, Images, Information, CategoryID) VALUES ('PROD367', N'Robot hút bụi lau nhà Xiaomi Vacuum H50 Pro', N'Xiaomi', N'["https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-1_2.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-2_1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-3_1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-4_1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-5_1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-6_1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-7_1.jpg", "https://cdn2.cellphones.com.vn/358x/media/catalog/product/r/o/robot-hut-bui-xiaomi-vacuum-h50-8_1.jpg"]', N'{"Thông tin chung": {"Chức năng": "Hút bụi lau sàn", "Dung tích ngăn chứa nước": "Nước sạch: 4L\nNước bẩn: 4L", "Lực hút": "15.000Pa", "Ứng dụng kết nối": "Xiaomi Home", "Pin": "4800mAh", "Công suất": "55W"}, "Tiện ích và tính năng": {"Tính năng": "Hỗ trợ tường ảo, Hỗ trợ lau nhà, Điều khiển qua ứng dụng, Tự động quay về đế sạc, Tự động điều chỉnh sức hút, Chống rối tóc - lông thú, Lưu trữ một bản đồ, Tự động hút bụi, Tự động giặt giẻ, Tự động sấy giẻ", "Tiện ích": "Điều khiển qua app Xiaomi Home và giọng nói\nHỗ trợ Google Assistant & Alexa\nTúi rác dùng ~75 ngày\nLau xoay kép 180rpm"}, "Thiết kế & Trọng lượng": {"Trọng lượng": "3.9kg", "Kích thước": "355 x 353.5 x 93mm"}, "Thông tin hãng": {"Hãng sản xuất": "Xiaomi"}, "Tiện ích": {"Tính năng khác": "Cánh tay cơ học mở rộng (chổi + mop) làm sạch sát cạnh\nĐiều hướng LDS + cảm biến ánh sáng cấu trúc 129°\nNhận diện thảm, tự nâng giẻ lau\nChống rối tóc kép (Y-comb + chổi cạnh)"}}', 'CAT2');
